const [firstName, lastName] = fullName.split(" ");
const initialGreeting = firstName + " " + lastName.slice(0, 1) + ".";

console.log(initialGreeting); // "Sarah C."`,exercises:[{id:"string-template-interpolation",title:"Template Literal Interpolator",difficulty:"Warm-up",codeSnippet:'// Example Use Case: String generation\nconst user = "Alice";\nconst greeting = `Hello, ${user}!`; // "Hello, Alice!"',conceptContext:"Template literals inside backticks (`) allow seamless variable and expression injection via standard ${} markers.",description:`Let's practice the most common way to build modern strings in JavaScript: using backticks and string interpolation!

